import { Events } from '@cornerstonejs/tools/enums';
import { getEnabledElement, utilities as csUtils } from '@cornerstonejs/core';
import type { Types } from '@cornerstonejs/core';

import { AnnotationTool } from '@cornerstonejs/tools';
import {
  addAnnotation,
  getAnnotations,
  removeAnnotation,
} from '@cornerstonejs/tools/annotation/annotationState';
import { isAnnotationLocked } from '@cornerstonejs/tools/annotation/annotationLocking';
import { isAnnotationVisible } from '@cornerstonejs/tools/annotation/annotationVisibility';
import { math } from '@cornerstonejs/tools/utilities';

import { drawing } from '@cornerstonejs/tools';
import { state } from '@cornerstonejs/tools';
import { viewportFilters } from '@cornerstonejs/tools/utilities';
import { triggerAnnotationRenderForViewportIds } from '@cornerstonejs/tools/utilities';
import {
  triggerAnnotationCompleted,
  triggerAnnotationModified,
} from '@cornerstonejs/tools/annotation/helpers/state';
import { setAnnotationVisibility } from '@cornerstonejs/tools/annotation/annotationVisibility';
import { setAnnotationLocked } from '@cornerstonejs/tools/annotation/annotationLocking';
import { cursors } from '@cornerstonejs/tools';

import type {
  EventTypes,
  ToolHandle,
  TextBoxHandle,
  PublicToolProps,
  ToolProps,
  SVGDrawingHelper,
  Annotation,
  Annotations,
} from '@cornerstonejs/tools/types';
import type { StyleSpecifier } from '@cornerstonejs/tools/types/AnnotationStyle';

enum AnnotationMode {
  POINTS = 'points',
  MOVABLE_POINTS = 'movable',
  DENTASCAN = 'dentascan',
}

interface LineSegment extends Annotation {
  metadata: Types.ViewReference & {
    toolName: string;
    cameraPosition?: Types.Point3;
    viewUp?: Types.Point3;
    // If the annotation is to indicate dentascan current section
    dentascan?: boolean;
    // If curve is made by hand or generated by interpolation
    handmade?: boolean;
    // Color of the annotation as a rgb string
    color?: string;
  };
  data: {
    text: string;
    handles: {
      points: Types.Point3[];
      activeHandleIndex: number | null;
      textBox: {
        hasMoved: boolean;
        worldPosition: Types.Point3;
        worldBoundingBox: {
          topLeft: Types.Point3;
          topRight: Types.Point3;
          bottomLeft: Types.Point3;
          bottomRight: Types.Point3;
        };
      };
    };
  };
}

class LineSegmentTool extends AnnotationTool {
  static toolName;

  _throttledCalculateCachedStats: Function;
  editData: {
    annotation: Annotation;
    viewportIdsToRender: string[];
    handleIndex?: number;
    movingTextBox?: boolean;
    newAnnotation?: boolean;
    hasMoved?: boolean;
    creation?: boolean;
  } | null;
  isDrawing: boolean;
  isHandleOutsideImage: boolean;

  constructor(
    toolProps: PublicToolProps = {},
    defaultToolProps: ToolProps = {
      supportedInteractionTypes: ['Mouse', 'Touch'],
      configuration: {
        shadow: true,
        getTextCallback,
        changeTextCallback,
        preventHandleOutsideImage: false,
      },
    }
  ) {
    super(toolProps, defaultToolProps);
  }

  removeLineSegmentAnnotation = uid => {
    removeAnnotation(uid);
  };

  addNewAnnotationWithMode = (element, points, mode, color, visibility): LineSegment => {
    // Create annotation
    const enabledElement = getEnabledElement(element);
    const { viewport, renderingEngine } = enabledElement;

    cursors.elementCursor.hideElementCursor(element);
    this.isDrawing = true;

    const camera = viewport.getCamera();
    const { viewPlaneNormal, viewUp } = camera;

    const referencedImageId = this.getReferencedImageId(
      viewport,
      points[0],
      viewPlaneNormal,
      viewUp
    );

    const FrameOfReferenceUID = viewport.getFrameOfReferenceUID();

    const annotation = {
      highlighted: true,
      invalidated: true,
      metadata: {
        dentascan: mode === AnnotationMode.DENTASCAN,
        handmade: mode === AnnotationMode.MOVABLE_POINTS,
        color: color,
        toolName: this.getToolName(),
        viewPlaneNormal: <Types.Point3>[...viewPlaneNormal],
        viewUp: <Types.Point3>[...viewUp],
        FrameOfReferenceUID,
        referencedImageId,
      },
      data: {
        text: '',
        handles: {
          points: points,
          activeHandleIndex: null,
          textBox: {
            hasMoved: false,
            worldPosition: <Types.Point3>[0, 0, 0],
            worldBoundingBox: {
              topLeft: <Types.Point3>[0, 0, 0],
              topRight: <Types.Point3>[0, 0, 0],
              bottomLeft: <Types.Point3>[0, 0, 0],
              bottomRight: <Types.Point3>[0, 0, 0],
            },
          },
        },
        label: '',
      },
      annotationUID: csUtils.uuidv4() as string,
    };
    const isVisible = visibility ?? mode !== AnnotationMode.MOVABLE_POINTS;
    const isLocked = mode !== AnnotationMode.MOVABLE_POINTS;
    setAnnotationVisibility(annotation.annotationUID, isVisible);
    setAnnotationLocked(annotation.annotationUID, isLocked);
    addAnnotation(annotation, element);

    const viewportIdsToRender = viewportFilters.getViewportIdsWithToolToRender(
      element,
      this.getToolName()
    );

    this.editData = {
      annotation,
      viewportIdsToRender,
      handleIndex: 1,
      movingTextBox: false,
      newAnnotation: true,
      hasMoved: false,
      creation: true,
    };
    this._activateDraw(element);

    triggerAnnotationRenderForViewportIds(viewportIdsToRender);

    // End annotation
    annotation.data.handles.activeHandleIndex = null;

    this._deactivateModify(element);
    this._deactivateDraw(element);
    cursors.elementCursor.resetElementCursor(element);

    if (this.isHandleOutsideImage && this.configuration.preventHandleOutsideImage) {
      removeAnnotation(annotation.annotationUID);
    }

    annotation.data.text = '';

    triggerAnnotationCompleted(annotation);

    triggerAnnotationRenderForViewportIds(viewportIdsToRender);

    this.editData = null;
    this.isDrawing = false;

    return annotation;
  };

  /**
   * Based on the current position of the mouse and the current imageId to create
   * a Length Annotation and stores it in the annotationManager
   *
   * @param evt -  EventTypes.NormalizedMouseEventType
   * @returns The annotation object.
   *
   */
  addNewAnnotation = (evt: EventTypes.InteractionEventType): LineSegment => {
    const eventDetail = evt.detail;
    const { currentPoints, element } = eventDetail;
    const worldPos = currentPoints.world;
    const enabledElement = getEnabledElement(element);
    const { viewport, renderingEngine } = enabledElement;

    cursors.elementCursor.hideElementCursor(element);
    this.isDrawing = true;

    const camera = viewport.getCamera();
    const { viewPlaneNormal, viewUp } = camera;

    const referencedImageId = this.getReferencedImageId(
      viewport,
      worldPos,
      viewPlaneNormal,
      viewUp
    );

    const FrameOfReferenceUID = viewport.getFrameOfReferenceUID();

    const annotation = {
      highlighted: true,
      invalidated: true,
      metadata: {
        dentascan: false,
        handmade: true,
        color: 'rgb(0, 255, 0)',
        toolName: this.getToolName(),
        viewPlaneNormal: <Types.Point3>[...viewPlaneNormal],
        viewUp: <Types.Point3>[...viewUp],
        FrameOfReferenceUID,
        referencedImageId,
        ...viewport.getViewReference({ points: [worldPos] }),
      },
      data: {
        text: '',
        handles: {
          points: [<Types.Point3>[...worldPos], <Types.Point3>[...worldPos]],
          activeHandleIndex: null,
          textBox: {
            hasMoved: false,
            worldPosition: <Types.Point3>[0, 0, 0],
            worldBoundingBox: {
              topLeft: <Types.Point3>[0, 0, 0],
              topRight: <Types.Point3>[0, 0, 0],
              bottomLeft: <Types.Point3>[0, 0, 0],
              bottomRight: <Types.Point3>[0, 0, 0],
            },
          },
        },
        label: '',
      },
    };

    addAnnotation(annotation, element);

    const viewportIdsToRender = viewportFilters.getViewportIdsWithToolToRender(
      element,
      this.getToolName()
    );

    this.editData = {
      annotation,
      viewportIdsToRender,
      handleIndex: 1,
      movingTextBox: false,
      newAnnotation: true,
      hasMoved: false,
      creation: true,
    };
    this._activateDraw(element);

    evt.preventDefault();

    triggerAnnotationRenderForViewportIds(viewportIdsToRender);

    return annotation;
  };

  /**
   * It returns if the canvas point is near the provided length annotation in the provided
   * element or not. A proximity is passed to the function to determine the
   * proximity of the point to the annotation in number of pixels.
   *
   * @param element - HTML Element
   * @param annotation - Annotation
   * @param canvasCoords - Canvas coordinates
   * @param proximity - Proximity to tool to consider
   * @returns Boolean, whether the canvas point is near tool
   */
  isPointNearTool = (
    element: HTMLDivElement,
    annotation: LineSegment,
    canvasCoords: Types.Point2,
    proximity: number
  ): boolean => {
    const enabledElement = getEnabledElement(element);
    const { viewport } = enabledElement;
    const { data } = annotation;
    const [point1, point2] = data.handles.points;
    const canvasPoint1 = viewport.worldToCanvas(point1);
    const canvasPoint2 = viewport.worldToCanvas(point2);

    const line = {
      start: {
        x: canvasPoint1[0],
        y: canvasPoint1[1],
      },
      end: {
        x: canvasPoint2[0],
        y: canvasPoint2[1],
      },
    };

    const distanceToPoint = math.lineSegment.distanceToPoint(
      [line.start.x, line.start.y],
      [line.end.x, line.end.y],
      [canvasCoords[0], canvasCoords[1]]
    );

    if (distanceToPoint <= proximity) {
      return true;
    }

    return false;
  };

  toolSelectedCallback = (evt: EventTypes.InteractionEventType, annotation: LineSegment): void => {
    const eventDetail = evt.detail;
    const { element } = eventDetail;

    annotation.highlighted = true;

    const viewportIdsToRender = viewportFilters.getViewportIdsWithToolToRender(
      element,
      this.getToolName()
    );

    this.editData = {
      annotation,
      viewportIdsToRender,
      movingTextBox: false,
    };

    this._activateModify(element);

    cursors.elementCursor.hideElementCursor(element);

    const enabledElement = getEnabledElement(element);
    const { renderingEngine } = enabledElement;

    triggerAnnotationRenderForViewportIds(viewportIdsToRender);

    evt.preventDefault();
  };

  handleSelectedCallback(
    evt: EventTypes.InteractionEventType,
    annotation: LineSegment,
    handle: ToolHandle
  ): void {
    const eventDetail = evt.detail;
    const { element } = eventDetail;
    const { data } = annotation;

    annotation.highlighted = true;

    let movingTextBox = false;
    let handleIndex;

    if ((handle as TextBoxHandle).worldPosition) {
      movingTextBox = true;
    } else {
      handleIndex = data.handles.points.findIndex(p => p === handle);
    }

    // Find viewports to render on drag.
    const viewportIdsToRender = viewportFilters.getViewportIdsWithToolToRender(
      element,
      this.getToolName()
    );

    this.editData = {
      annotation,
      viewportIdsToRender,
      handleIndex,
      movingTextBox,
    };
    this._activateModify(element);

    cursors.elementCursor.hideElementCursor(element);

    triggerAnnotationRenderForViewportIds(viewportIdsToRender);

    evt.preventDefault();
  }

  _manageClickCallback = (evt: EventTypes.InteractionEventType): void => {
    const eventDetail = evt.detail;
    // @ts-ignore
    const { mouseButton } = eventDetail;
    //Skip first click when new annotation if created
    if (this.editData.creation) {
      this.editData.creation = false;
      return;
    }

    // Left click
    if (mouseButton === 1) {
      this._prolongateCallback(evt);
    }
    // Right click
    else if (mouseButton === 2) {
      this._endCallback(evt);
    }
  };

  _endCallback = (evt: EventTypes.InteractionEventType): void => {
    const eventDetail = evt.detail;
    // @ts-ignore
    const { element, currentPoints, mouseButton } = eventDetail;

    const { annotation, viewportIdsToRender, newAnnotation, hasMoved } = this.editData;
    const { data } = annotation;

    if (newAnnotation && !hasMoved) {
      // when user starts the drawing by click, and moving the mouse, instead
      // of click and drag
      return;
    }

    data.handles.activeHandleIndex = null;

    this._deactivateModify(element);
    this._deactivateDraw(element);
    cursors.elementCursor.resetElementCursor(element);

    if (this.isHandleOutsideImage && this.configuration.preventHandleOutsideImage) {
      removeAnnotation(annotation.annotationUID);
    }

    if (newAnnotation) {
      annotation.data.text = '';

      triggerAnnotationCompleted(annotation);

      triggerAnnotationRenderForViewportIds(viewportIdsToRender);
    } else {
      triggerAnnotationModified(annotation, element);
    }

    this.editData = null;
    this.isDrawing = false;
  };

  // Prolongate polyline when left click during annotation creation
  _prolongateCallback = (evt: EventTypes.InteractionEventType): void => {
    const eventDetail = evt.detail;
    const { currentPoints } = eventDetail;
    const worldPos = currentPoints.world;

    const { annotation, viewportIdsToRender, handleIndex } = this.editData;
    const { data } = annotation;

    data.handles.points[handleIndex] = [...worldPos];
    data.handles.points.push(<Types.Point3>[...worldPos]);
    this.editData.handleIndex += 1;

    evt.preventDefault();

    triggerAnnotationRenderForViewportIds(viewportIdsToRender);
  };

  _dragCallback = (evt: EventTypes.InteractionEventType): void => {
    this.isDrawing = true;
    const eventDetail = evt.detail;
    const { element } = eventDetail;

    const { annotation, viewportIdsToRender, handleIndex, movingTextBox } = this.editData;
    const { data } = annotation;

    if (movingTextBox) {
      // Drag mode - moving text box
      const { deltaPoints } = eventDetail as EventTypes.MouseDragEventDetail;
      const worldPosDelta = deltaPoints.world;

      const { textBox } = data.handles;
      const { worldPosition } = textBox;

      worldPosition[0] += worldPosDelta[0];
      worldPosition[1] += worldPosDelta[1];
      worldPosition[2] += worldPosDelta[2];

      textBox.hasMoved = true;
    } else if (handleIndex === undefined) {
      // Drag mode - moving handle
      const { deltaPoints } = eventDetail as EventTypes.MouseDragEventDetail;
      const worldPosDelta = deltaPoints.world;

      const points = data.handles.points;

      points.forEach(point => {
        point[0] += worldPosDelta[0];
        point[1] += worldPosDelta[1];
        point[2] += worldPosDelta[2];
      });
      annotation.invalidated = true;
    } else {
      // Move mode - after double click, and mouse move to draw
      const { currentPoints } = eventDetail;
      const worldPos = currentPoints.world;

      data.handles.points[handleIndex] = [...worldPos];
      annotation.invalidated = true;
    }

    this.editData.hasMoved = true;

    const enabledElement = getEnabledElement(element);
    const { renderingEngine } = enabledElement;

    triggerAnnotationRenderForViewportIds(viewportIdsToRender);
  };

  touchTapCallback = (evt: EventTypes.TouchTapEventType) => {
    if (evt.detail.taps == 2) {
      this.doubleClickCallback(evt);
    }
  };

  doubleClickCallback = (evt: EventTypes.TouchTapEventType): void => {
    const eventDetail = evt.detail;
    const { element } = eventDetail;
    let annotations = getAnnotations(this.getToolName(), element);

    annotations = this.filterInteractableAnnotationsForElement(element, annotations);

    if (!annotations?.length) {
      return;
    }

    const clickedAnnotation = annotations.find(annotation =>
      this.isPointNearTool(
        element,
        annotation as LineSegment,
        eventDetail.currentPoints.canvas,
        6 // Todo: get from configuration
      )
    );

    if (!clickedAnnotation) {
      return;
    }

    const annotation = clickedAnnotation as LineSegment;

    this.configuration.changeTextCallback(
      clickedAnnotation,
      evt.detail,
      this._doneChangingTextCallback.bind(this, element, annotation)
    );

    this.editData = null;
    this.isDrawing = false;

    // This double click was handled and the dialogue was displayed.
    // No need for any other listener to handle it too - stopImmediatePropagation
    // helps ensure this primarily so that no other listeners on the target element
    // get called.
    evt.stopImmediatePropagation();
    evt.preventDefault();
  };

  _doneChangingTextCallback(element, annotation, updatedText): void {
    annotation.data.text = updatedText;

    const enabledElement = getEnabledElement(element);

    const viewportIdsToRender = viewportFilters.getViewportIdsWithToolToRender(
      element,
      this.getToolName()
    );
    triggerAnnotationRenderForViewportIds(viewportIdsToRender);

    // Dispatching annotation modified
    triggerAnnotationModified(annotation, element);
  }

  cancel = (element: HTMLDivElement) => {
    // If it is mid-draw or mid-modify
    if (this.isDrawing) {
      this.isDrawing = false;
      this._deactivateDraw(element);
      this._deactivateModify(element);
      cursors.elementCursor.resetElementCursor(element);

      const { annotation, viewportIdsToRender, newAnnotation } = this.editData;
      const { data } = annotation;

      annotation.highlighted = false;
      data.handles.activeHandleIndex = null;

      triggerAnnotationRenderForViewportIds(viewportIdsToRender);

      if (newAnnotation) {
        triggerAnnotationCompleted(annotation);
      }

      this.editData = null;
      return annotation.annotationUID;
    }
  };

  _activateModify = (element: HTMLDivElement) => {
    state.isInteractingWithTool = true;

    element.addEventListener(Events.MOUSE_UP, this._endCallback as EventListener);
    element.addEventListener(Events.MOUSE_DRAG, this._dragCallback as EventListener);
    element.addEventListener(Events.MOUSE_CLICK, this._endCallback as EventListener);

    element.addEventListener(Events.TOUCH_TAP, this._endCallback as EventListener);
    element.addEventListener(Events.TOUCH_END, this._endCallback as EventListener);
    element.addEventListener(Events.TOUCH_DRAG, this._dragCallback as EventListener);
  };

  _deactivateModify = (element: HTMLDivElement) => {
    state.isInteractingWithTool = false;

    element.removeEventListener(Events.MOUSE_UP, this._endCallback as EventListener);
    element.removeEventListener(Events.MOUSE_DRAG, this._dragCallback as EventListener);
    element.removeEventListener(Events.MOUSE_CLICK, this._endCallback as EventListener);

    element.removeEventListener(Events.TOUCH_TAP, this._endCallback as EventListener);
    element.removeEventListener(Events.TOUCH_DRAG, this._dragCallback as EventListener);
    element.removeEventListener(Events.TOUCH_END, this._endCallback as EventListener);
  };

  _activateDraw = (element: HTMLDivElement) => {
    state.isInteractingWithTool = true;

    element.addEventListener(Events.MOUSE_UP, this._manageClickCallback as EventListener);
    element.addEventListener(Events.MOUSE_DRAG, this._dragCallback as EventListener);
    element.addEventListener(Events.MOUSE_MOVE, this._dragCallback as EventListener);
    element.addEventListener(Events.MOUSE_CLICK, this._manageClickCallback as EventListener);

    element.addEventListener(Events.TOUCH_TAP, this._manageClickCallback as EventListener);
    element.addEventListener(Events.TOUCH_END, this._manageClickCallback as EventListener);
    element.addEventListener(Events.TOUCH_DRAG, this._dragCallback as EventListener);
  };

  _deactivateDraw = (element: HTMLDivElement) => {
    state.isInteractingWithTool = false;

    element.removeEventListener(Events.MOUSE_UP, this._manageClickCallback as EventListener);
    element.removeEventListener(Events.MOUSE_DRAG, this._dragCallback as EventListener);
    element.removeEventListener(Events.MOUSE_MOVE, this._dragCallback as EventListener);
    element.removeEventListener(Events.MOUSE_CLICK, this._manageClickCallback as EventListener);

    element.removeEventListener(Events.TOUCH_TAP, this._manageClickCallback as EventListener);
    element.removeEventListener(Events.TOUCH_END, this._manageClickCallback as EventListener);
    element.removeEventListener(Events.TOUCH_DRAG, this._dragCallback as EventListener);
  };

  /**
   * it is used to draw the length annotation in each
   * request animation frame. It calculates the updated cached statistics if
   * data is invalidated and cache it.
   *
   * @param enabledElement - The Cornerstone's enabledElement.
   * @param svgDrawingHelper - The svgDrawingHelper providing the context for drawing.
   */
  renderAnnotation = (
    enabledElement: Types.IEnabledElement,
    svgDrawingHelper: SVGDrawingHelper
  ): boolean => {
    let renderStatus = false;
    const { viewport } = enabledElement;
    const { element } = viewport;

    let annotations = getAnnotations(this.getToolName(), element);

    // Todo: We don't need this anymore, filtering happens in triggerAnnotationRender
    if (!annotations?.length) {
      return renderStatus;
    }

    // CHANGES: Comment here in order to see lineSegmentTool everywhere in volume,
    // not just where it was created

    // annotations = this.filterInteractableAnnotationsForElement(
    //   element,
    //   annotations
    // );
    //
    if (!annotations?.length) {
      return renderStatus;
    }

    const styleSpecifier: StyleSpecifier = {
      toolGroupId: this.toolGroupId,
      toolName: this.getToolName(),
      viewportId: enabledElement.viewport.id,
    };

    // Draw SVG
    for (let i = 0; i < annotations.length; i++) {
      const annotation = annotations[i] as LineSegment;
      const { annotationUID, data } = annotation;
      const { handles, text } = data;
      const { points, activeHandleIndex } = handles;

      styleSpecifier.annotationUID = annotationUID;

      const { lineWidth, lineDash } = this.getAnnotationStyle({
        annotation,
        styleSpecifier,
      });
      const color = annotation.metadata.color ?? 'rgb(255, 255, 255)';

      const canvasCoordinates = points.map(p => viewport.worldToCanvas(p));

      let activeHandleCanvasCoords;

      if (!isAnnotationVisible(annotationUID)) {
        continue;
      }

      if (!isAnnotationLocked(annotationUID) && !this.editData && activeHandleIndex !== null) {
        // Not locked or creating and hovering over handle, so render handle.
        activeHandleCanvasCoords = [canvasCoordinates[activeHandleIndex]];
      }

      const handleGroupUID = '0';

      if (annotation.metadata.handmade) {
        drawing.drawHandles(svgDrawingHelper, annotationUID, handleGroupUID, canvasCoordinates, {
          color,
          lineWidth,
        });
      }

      let lineUID = 1;
      for (let i = 0; i < canvasCoordinates.length - 1; i++) {
        drawing.drawLine(
          svgDrawingHelper,
          annotationUID,
          `${lineUID}`,
          canvasCoordinates[i],
          canvasCoordinates[i + 1],
          {
            color,
            width: lineWidth,
            lineDash: lineDash,
          }
        );
        lineUID += 3;
      }

      renderStatus = true;

      // If rendering engine has been destroyed while rendering
      if (!viewport.getRenderingEngine()) {
        console.warn('Rendering Engine has been destroyed');
        return renderStatus;
      }

      if (!text) {
        continue;
      }

      const options = this.getLinkedTextBoxStyle(styleSpecifier, annotation);
      if (!options.visibility) {
        data.handles.textBox = {
          hasMoved: false,
          worldPosition: <Types.Point3>[0, 0, 0],
          worldBoundingBox: {
            topLeft: <Types.Point3>[0, 0, 0],
            topRight: <Types.Point3>[0, 0, 0],
            bottomLeft: <Types.Point3>[0, 0, 0],
            bottomRight: <Types.Point3>[0, 0, 0],
          },
        };
        continue;
      }

      // Need to update to sync w/ annotation while unlinked/not moved
      if (!data.handles.textBox.hasMoved) {
        // linked to the point that doesn't have the arrowhead by default
        const canvasTextBoxCoords = canvasCoordinates[1];

        data.handles.textBox.worldPosition = viewport.canvasToWorld(canvasTextBoxCoords);
      }

      const textBoxPosition = viewport.worldToCanvas(data.handles.textBox.worldPosition);

      const textBoxUID = '1';
      const boundingBox = drawing.drawLinkedTextBox(
        svgDrawingHelper,
        annotationUID,
        textBoxUID,
        [text],
        textBoxPosition,
        canvasCoordinates,
        {},
        options
      );

      const { x: left, y: top, width, height } = boundingBox;

      data.handles.textBox.worldBoundingBox = {
        topLeft: viewport.canvasToWorld([left, top]),
        topRight: viewport.canvasToWorld([left + width, top]),
        bottomLeft: viewport.canvasToWorld([left, top + height]),
        bottomRight: viewport.canvasToWorld([left + width, top + height]),
      };
    }

    return renderStatus;
  };

  _isInsideVolume(index1, index2, dimensions) {
    return (
      csUtils.indexWithinDimensions(index1, dimensions) &&
      csUtils.indexWithinDimensions(index2, dimensions)
    );
  }

  // Interact with lineSegmentTool everywhere in the volume, not just in the layer where it was created
  filterInteractableAnnotationsForElement(
    element: HTMLDivElement,
    annotations: Annotations
  ): Annotations | undefined {
    return annotations;
  }
}

function getTextCallback(doneChangingTextCallback) {
  return doneChangingTextCallback(prompt('Enter your annotation:'));
}

function changeTextCallback(data, eventData, doneChangingTextCallback) {
  return doneChangingTextCallback(prompt('Enter your annotation:'));
}

LineSegmentTool.toolName = 'LineSegment';
export default LineSegmentTool;
