import { PubSubService } from '@ohif/core';
import axios from 'axios';
import { NumberPair, POINTS, Position } from '../../types/Panoramic';

interface ResultInfo3d {
  id?: number;
  analyze_id?: number;
  segmented_anatomy?: ArrayBuffer;
  segmented_diseases?: ArrayBuffer;
  panoramic?: Float32Array;
  diseases: { pos: Position; subtype: string; confidence: number }[];
  metadata: {
    dentascan_thickness: number;
    min_max_tissue_layer: NumberPair;
    points: POINTS;
  };
  teeth_axes: { [tooth: string]: number[] };
}

interface ResultInfoFull {
  id?: number;
  image_id: number;
  date: string;
  api_version: string;
  app_version: string;
  analyze_uuid: string;
  status: 'ANALYSED' | 'IN_PROGRESS' | 'VALIDATED';
  examIndication: string;
  type: number;
  data3d: ResultInfo3d;
}

export default class DatabaseService extends PubSubService {
  private connectionString: string = '';
  private imageId: number = -1;
  private analyzeId: number = -1;

  static EVENTS = {};

  public static REGISTRATION = {
    name: 'databaseService',
    create: (): DatabaseService => {
      return new DatabaseService();
    },
  };

  constructor() {
    super(DatabaseService.EVENTS);
  }

  public setConnectionString = (connectionString: string) => {
    this.connectionString = connectionString;
  };

  public getConnectionString = () => {
    return this.connectionString;
  };

  public setImageId = (imageId: number) => {
    this.imageId = imageId;
  };

  public getImageId = () => {
    return this.imageId;
  };

  public setAnalyzeId = (analyzeId: number) => {
    this.analyzeId = analyzeId;
  };

  public getAnalyzeId = () => {
    return this.analyzeId;
  };

  private isValidAnalyze = (): boolean => {
    return this.connectionString !== '' && this.analyzeId !== -1;
  };

  public getImageContentById = async (): Promise<string | null> => {
    if (this.connectionString === '' || this.imageId === -1) {
      return null;
    }

    try {
      const response = await axios.get(this.connectionString + `/image/${this.imageId}`);
      return response.data.data;
    } catch (e) {
      throw new Error(`Error in getImageContentById: ${e}`);
    }
  };

  public createAnalyze = async (analyzeUuid: string): Promise<boolean | null> => {
    if (this.connectionString === '' || this.imageId === -1) {
      return null;
    }

    const emptyAnalyze: ResultInfoFull = {
      image_id: this.imageId,
      date: new Date().toISOString(),
      api_version: '1.1.0',
      app_version: '1.0.1',
      analyze_uuid: analyzeUuid,
      status: 'ANALYSED',
      examIndication: '',
      type: 3,
      data3d: {
        diseases: [],
        metadata: {
          dentascan_thickness: 0,
          min_max_tissue_layer: [0, 0],
          points: {
            controlPoints: [],
            curvePoints: [],
            innerPoints: [],
            normals: [],
            outerPoints: [],
          },
        },
        teeth_axes: {},
      },
    };

    try {
      const response = await axios.post(this.connectionString + '/analyze', emptyAnalyze);
      if (!response.data) {
        return false;
      }

      this.analyzeId = (await this.getAnalyzeByImageId()).id;
      return response.data === 'success';
    } catch (e) {
      throw new Error(`Error in createAnalyze: ${e}`);
    }
  };

  public updateImageDescription = async (description: string): Promise<boolean | null> => {
    if (!this.isValidAnalyze()) {
      return null;
    }

    try {
      const response = await axios.patch(
        this.connectionString + `/image/${this.analyzeId}/description`,
        { description }
      );
      if (!response.data) {
        return false;
      }
      return response.data.status === 'success';
    } catch (e) {
      throw new Error(`Error in updateImageDescription: ${e}`);
    }
  };

  public modifyAnalyzeSegmentedAnatomy = async (
    segmented_anatomy: ArrayBuffer
  ): Promise<boolean | null> => {
    if (!this.isValidAnalyze()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analyzeId}/segmented_anatomy`,
        segmented_anatomy,
        { headers: { 'Content-Type': 'application/octet-stream' } }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalyzeSegmentedAnatomy: ${e}`);
    }
  };

  public modifyAnalyzeSegmentedDiseases = async (
    segmented_diseases: ArrayBuffer
  ): Promise<boolean | null> => {
    if (!this.isValidAnalyze()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analyzeId}/segmented_diseases`,
        segmented_diseases,
        { headers: { 'Content-Type': 'application/octet-stream' } }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalyzeSegmentedDiseases: ${e}`);
    }
  };

  public modifyAnalyzePanoramic = async (panoramic: Float32Array): Promise<boolean | null> => {
    if (!this.isValidAnalyze()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analyzeId}/panoramic`,
        panoramic,
        { headers: { 'Content-Type': 'application/octet-stream' } }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalyzePanoramic: ${e}`);
    }
  };

  public modifyAnalyzeDiseases = async (
    diseases: ResultInfo3d['diseases']
  ): Promise<boolean | null> => {
    if (!this.isValidAnalyze()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analyzeId}/diseases`,
        { diseases }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalyzeDiseases: ${e}`);
    }
  };

  public modifyAnalyzeMetadata = async (
    metadata: ResultInfo3d['metadata']
  ): Promise<boolean | null> => {
    if (!this.isValidAnalyze()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analyzeId}/metadata`,
        { metadata }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalyzeMetadata: ${e}`);
    }
  };

  public modifyAnalyzeTeethAxes = async (
    teeth_axes: ResultInfo3d['teeth_axes']
  ): Promise<boolean | null> => {
    if (!this.isValidAnalyze()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analyzeId}/teeth_axes`,
        { teeth_axes }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalyzeTeethAxes: ${e}`);
    }
  };

  public modifyAnalyzeStatus = async (
    status: ResultInfoFull['status']
  ): Promise<boolean | null> => {
    if (!this.isValidAnalyze()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analyzeId}/status`,
        { status }
      );
      if (!response.data) {
        return false;
      }
      return response.data === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalyzeStatus: ${e}`);
    }
  };

  public modifyAnalyzeExamIndication = async (examIndication: string): Promise<boolean | null> => {
    if (!this.isValidAnalyze()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analyzeId}/examIndication`,
        { examIndication }
      );
      if (!response.data) {
        return false;
      }
      return response.data === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalyzeExamIndication: ${e}`);
    }
  };

  public getAnalyzeById = async (): Promise<ResultInfoFull | null> => {
    if (!this.isValidAnalyze()) {
      return null;
    }

    try {
      const response = await axios.get(this.connectionString + `/analyze/${this.analyzeId}`);
      return response.data.data;
    } catch (e) {
      throw new Error(`Error in getAnalyzeById: ${e}`);
    }
  };

  public getAnalyzeByImageId = async (): Promise<ResultInfoFull | null> => {
    if (this.connectionString === '' || this.imageId === -1) {
      return null;
    }

    try {
      const response = await axios.get(this.connectionString + `/analyze/image/${this.imageId}`);
      this.analyzeId = response.data.data.id;
      return response.data.data;
    } catch (e) {
      throw new Error(`Error in getAnalyzeByImageId: ${e}`);
    }
  };
}
